<template>
    <div class="detail">
       <h1>标题：{{blog.title}}</h1>
      <p>内容：{{blog.content}}</p>
      <p>作者{{blog.author}}</p>
      <ul>
        <li v-for="categorie in blog.categories">{{categorie}}</li>
      </ul>
      <button v-on:click = "del()">删除博客</button>
     <router-link :to="'/edit/' + this.id">编辑博客</router-link>
    </div>
</template>
<script>
  import axios from "axios"
    export default{
      name:"detailBlog",
      data(){
        return {
          id:this.$route.params.id,
          blog:{}
        }
      },
      created(){
        axios.get("/posts/" + this.id + ".json")
          .then((data)=>{
               return data.data;
            })
          .then( (data)=> {
          this.blog = data;
        })
      },
      methods:{
        del(){
         axios.delete("/posts/" + this.id + ".json")
            .then(response =>{
              this.$router.push({path:"/"})
            })
        }
      }
    }
</script>
<style scoped>
    .detail{
      max-width:960px;
      margin:20px auto;
      background:#eee;
      padding:20px;
    }
  h1{
    margin-bottom:20px;
  }
</style>



