<template>
  <div class="addBlog" >
    <form v-show="!blog.submited">
      <h2>编辑博客</h2>
      <p><label for="theme">主题:</label></p>
      <input type="text" id="theme" v-model="blog.title" required><br>
      <p><label for="content">内容:</label></p>
      <textarea id="content" v-model="blog.content" ></textarea><br/>
      <p>分类:</p>
      <div class="check">
        <label>Vue.js<input type="checkbox" value="Vue.js" v-model="blog.categories"/></label>
        <label>Angular4<input type="checkbox" value="Angular4" v-model="blog.categories"/></label>
        <label>Node.js<input type="checkbox"value="Node.js" v-model="blog.categories"/></label>
        <label>React.js<input type="checkbox" value="React.js" v-model="blog.categories"/></label>
      </div>
      <p>作者:</p>
      <select  v-model="blog.author">
        <option  v-for="a in blog.authors" >{{a}}</option>
      </select>
      <p><button v-on:click.prevent = "post">编辑完成</button></p>
    </form>
    <p v-show="blog.submited">您的博客添加成功！</p>
    <hr>
    <div class="preview">
      <h2>博客总览</h2>
      <p>博客标题:   {{blog.title}}</p>
      <p>博客内容:   {{blog.content}}</p>
      <p>博客作者:   {{blog.author}}</p>
      <p>博客分类:</p>
      <ul>
        <li v-for="c in blog.categories">{{c}}</li>
      </ul>
    </div>


  </div>
</template>
<script>
  import axios from "axios"
  export default {
    name: 'AddBlog',
    data () {
      return {
        id:this.$route.params.id,
        blog:{
        }
      }
    },
    methods:{
      fetchData(){
      axios.get("/posts/" + this.id + ".json")
         .then(response =>{
          this.blog = response.data
         })
      },
      post(){
        axios.put("/posts/" + this.id + ".json",
          this.blog
        ).then( (data) =>{
          // console.log(data)
          this.blog.submited = true;
        })
      }
    },created(){
      this.fetchData();
    }
  }
</script>

<style scoped>
  .addBlog{
    width: 600px;
    height:700px;
    margin:0 auto;
    padding:20px;
    font-weight:900;

  }
  #content{
    margin-top: 10px;
  }
  li{
    list-style-type:none;
  }
  #theme{
    width: 100%;
    padding: 10px 5px;
  }
  #content{
    width: 100%;
    height:200px;
    padding: 10px 5px;
  }
  p{
    margin: 15px 0;
  }
  label input{
    margin-left:10px;
  }
  select{
    width: 100%;
    padding:5px;
    margin: 10px 0;
  }
  button{
    background:#d80b31;
    width: 70px;
    height:40px;
    padding:5px 5px;
    border-radius:5px;
    outline: none;
    margin:50px 0;
    color: white;
  }
  .preview{
    text-align: center;
  }
</style>



