<template>
  <div id="show-blogs"v-theme:column="'narrow'">
    <div class="content">
      <h2>博客总览</h2>
      <input type="text" placeholder="search blogs" class="view" v-model="search">
      <ul>
        <li class="blog-list" v-for="(blog, index) in filterBlogs">
          <router-link id="de" v-bind:to="'/blog/' + blog.id"><h2 v-rainbow>{{blog.title | toBig |toSmall}}</h2>
          </router-link>
          <p class="content">{{blog.content}}</p>
          <!--<button v-on:click = "del(index)">删除</button> 只删除显示的数据，数据库没有删除-->

        </li>
      </ul>
      <!--<add-blog></add-blog>-->
    </div>
  </div>
</template>

<script>
  import axios from "axios"
  export default {
    name: 'ShowBlog',
    data() {
      return {
        blogs: [],
        search: "",

      }
    },
    // props: {
    //   bl: {
    //     type: Array,
    //   }
    // },
    //请求本地数据
    created() {
      axios.get("/posts.json")//为什么static/posts.json ./static/posts.json ../static/posts.json ./../static/posts.json./static/posts.json都可以
        .then(function (data) {
         // this.blogs = data.body.slice(0,10);
          return data.data;
        })
        .then((data) =>{
            var blogsArray = [];
            for (let key in data) {
              data[key].id = key;
              blogsArray.push(data[key]);
              // console.log(data[key]);
            }
            this.blogs = blogsArray;
            // console.log(blogsArray)
          })
    },
    computed: {
      filterBlogs: function () {
        return this.blogs.filter((blog) => {
          return blog.title.match(this.search);
        })
      }
    },
    methods: {
      // del(index){
      //   this.blogs.splice(index,1);
      // }

    },
    //局部过滤器
    filters: {
      "toSmall": function (value) {
        return value.toLowerCase();
      }
      // toSmall(value){
      //   return value.toLowerCase();
      // }
    },
    //局部自定义指令
    directives: {
      'rainbow': {
        bind(el, binding, vnode) {
          el.style.color = "#" + Math.random().toString(16).slice(2, 8);
        }
      }
    }
  }
</script>

<style>

  #show-blogs {
    margin: 40px auto;
    width: 800px;
    /*position: absolute;*/
    /*left: calc(50% - 380px);*/
  }

  h2 {
    margin-bottom: 20px;
  }

  .view {
    width: 95%;
    padding: 8px 20px;
  }

  .blog-list {
    list-style-type: none;
    width: 95%;
    height: 140px;
    background: #ddd;
    padding: 20px;
    margin: 15px 0;
  }

  #de {
    text-decoration: none;
  }
</style>



